namespace sv_0caae1f81ebd4f21b031c134b9534000.Services;

public class WizardData
{
    // Step 1
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2
    public List<JobHistoryEntry> JobHistory { get; set; } = new();

    // Step 3
    public List<ReferenceContact> References { get; set; } = new();

    // Progress tracking
    public HashSet<int> CompletedSteps { get; set; } = new();
}

public class JobHistoryEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;

namespace sv_0caae1f81ebd4f21b031c134b9534000.Services;

/// <summary>
/// Singleton service that stores wizard data keyed by session cookie ID.
/// Because it lives outside any single circuit or SSR scope, both the static
/// layout (progress bar) and interactive pages can read/write the same data.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardData> _sessions = new();

    public WizardData GetOrCreate(string sessionId) =>
        _sessions.GetOrAdd(sessionId, _ => new WizardData());
}

using Microsoft.AspNetCore.Components;
using sv_0caae1f81ebd4f21b031c134b9534000.Services;

namespace sv_0caae1f81ebd4f21b031c134b9534000.Components.Pages.Apply;

/// <summary>
/// Base class for every wizard step page. Resolves the session ID across the
/// static-SSR → interactive-circuit boundary using PersistentComponentState:
///
///   • During prerendering the layout passes the session ID as a CascadingValue
///     (the layout is static and has HttpContext access to read the cookie).
///   • This base class captures that value and registers it for persistence.
///   • When the interactive circuit starts, OnInitialized runs again — this time
///     the cascading value is gone, so we restore the session ID from the
///     persisted state instead.
/// </summary>
public abstract class WizardStepBase : ComponentBase, IDisposable
{
    [Inject] protected WizardStateService StateService { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected NavigationManager Navigation { get; set; } = default!;

    [CascadingParameter(Name = "WizardSessionId")]
    private string? CascadedSessionId { get; set; }

    protected string SessionId { get; private set; } = "";
    protected WizardData Data { get; private set; } = new();

    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", SessionId);
            return Task.CompletedTask;
        });

        if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            // Interactive circuit — restore from persisted prerender state
            SessionId = restored ?? "";
        }
        else
        {
            // Prerendering — read from the cascading value set by WizardLayout
            SessionId = CascadedSessionId ?? "";
        }

        Data = StateService.GetOrCreate(SessionId);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

