@inherits LayoutComponentBase
@inject sv_0caae1f81ebd4f21b031c134b9534000.Services.WizardStateService StateService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

@{
    var sessionId = HttpContextAccessor.HttpContext?.Items["WizardSessionId"]?.ToString() ?? "";
    var completedSteps = string.IsNullOrEmpty(sessionId)
        ? new HashSet<int>()
        : StateService.GetOrCreate(sessionId).CompletedSteps;

    var path = Navigation.ToAbsoluteUri(Navigation.Uri).AbsolutePath.TrimEnd('/');
    var currentStep = path switch
    {
        "/apply/experience" => 2,
        "/apply/references" => 3,
        "/apply/review"     => 4,
        _                   => 1
    };
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="wizard-header px-4 py-3">
            <h6 class="mb-2">Job Application &mdash; Step @currentStep of 4</h6>

            <div class="wizard-steps d-flex gap-2 mb-2">
                @for (int i = 0; i < steps.Length; i++)
                {
                    var step = i + 1;
                    var css = step == currentStep ? "current"
                            : completedSteps.Contains(step) ? "completed"
                            : "";
                    <a href="@steps[i].Url" class="wizard-step @css">
                        <span class="step-number">@step</span>
                        <span class="step-label">@steps[i].Label</span>
                    </a>
                }
            </div>

            <div class="progress" style="height: 4px;">
                <div class="progress-bar" role="progressbar"
                     style="width: @(currentStep * 25)%"></div>
            </div>
        </div>

        <article class="content px-4">
            <CascadingValue Value="@sessionId" Name="WizardSessionId">
                @Body
            </CascadingValue>
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private static readonly (string Url, string Label)[] steps =
    {
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience",    "Experience"),
        ("/apply/references",    "References"),
        ("/apply/review",        "Review")
    };
}

.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.wizard-header {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
}

.wizard-steps {
    flex-wrap: wrap;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.35rem 0.75rem;
    border-radius: 0.375rem;
    border: 1px solid #dee2e6;
    text-decoration: none;
    color: #6c757d;
    font-size: 0.85rem;
    transition: all 0.15s;
}

.wizard-step:hover {
    background-color: #e9ecef;
    text-decoration: none;
    color: #495057;
}

.wizard-step.current {
    background-color: #0d6efd;
    border-color: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.wizard-step.completed {
    background-color: #d1e7dd;
    border-color: #badbcc;
    color: #0f5132;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.4rem;
    height: 1.4rem;
    border-radius: 50%;
    background: rgba(0, 0, 0, 0.1);
    font-size: 0.75rem;
    font-weight: 700;
}

.wizard-step.current .step-number {
    background: rgba(255, 255, 255, 0.25);
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

    .sidebar {
        width: 250px;
        height: 100vh;
        position: sticky;
        top: 0;
    }

    .wizard-header {
        position: sticky;
        top: 0;
        z-index: 1;
    }

    .wizard-header, article {
        padding-left: 2rem !important;
        padding-right: 1.5rem !important;
    }
}

#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    box-sizing: border-box;
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

    #blazor-error-ui .dismiss {
        cursor: pointer;
        position: absolute;
        right: 0.75rem;
        top: 0.5rem;
    }

