@inherits LayoutComponentBase
@inject sv_0caae1f81ebd4f21b031c134b9534000.Services.WizardStateService StateService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

@{
    var sessionId = HttpContextAccessor.HttpContext?.Items["WizardSessionId"]?.ToString() ?? "";
    var completedSteps = string.IsNullOrEmpty(sessionId)
        ? new HashSet<int>()
        : StateService.GetOrCreate(sessionId).CompletedSteps;

    var path = Navigation.ToAbsoluteUri(Navigation.Uri).AbsolutePath.TrimEnd('/');
    var currentStep = path switch
    {
        "/apply/experience" => 2,
        "/apply/references" => 3,
        "/apply/review"     => 4,
        _                   => 1
    };
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="wizard-header px-4 py-3">
            <h6 class="mb-2">Job Application &mdash; Step @currentStep of 4</h6>

            <div class="wizard-steps d-flex gap-2 mb-2">
                @for (int i = 0; i < steps.Length; i++)
                {
                    var step = i + 1;
                    var css = step == currentStep ? "current"
                            : completedSteps.Contains(step) ? "completed"
                            : "";
                    <a href="@steps[i].Url" class="wizard-step @css">
                        <span class="step-number">@step</span>
                        <span class="step-label">@steps[i].Label</span>
                    </a>
                }
            </div>

            <div class="progress" style="height: 4px;">
                <div class="progress-bar" role="progressbar"
                     style="width: @(currentStep * 25)%"></div>
            </div>
        </div>

        <article class="content px-4">
            <CascadingValue Value="@sessionId" Name="WizardSessionId">
                @Body
            </CascadingValue>
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private static readonly (string Url, string Label)[] steps =
    {
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience",    "Experience"),
        ("/apply/references",    "References"),
        ("/apply/review",        "Review")
    };
}

arguments.file_text:
@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>Personal Info — Job Application</PageTitle>

<h1>Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input type="text" class="form-control" @bind="Data.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input type="email" class="form-control" @bind="Data.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void Next()
    {
        Data.CompletedSteps.Add(1);
        Navigation.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase
@using sv_0caae1f81ebd4f21b031c134b9534000.Services

<PageTitle>Experience — Job Application</PageTitle>

<h1>Work Experience</h1>

@foreach (var entry in Data.JobHistory)
{
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input type="text" class="form-control" @bind="entry.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input type="text" class="form-control" @bind="entry.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input type="text" class="form-control" @bind="entry.Years" />
        </div>
        <button class="btn btn-outline-danger btn-sm align-self-end"
                @onclick="() => RemoveEntry(entry)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Job</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddEntry() => Data.JobHistory.Add(new());
    private void RemoveEntry(JobHistoryEntry entry) => Data.JobHistory.Remove(entry);
    private void Back() => Navigation.NavigateTo("/apply/personal-info");

    private void Next()
    {
        Data.CompletedSteps.Add(2);
        Navigation.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase
@using sv_0caae1f81ebd4f21b031c134b9534000.Services

<PageTitle>References — Job Application</PageTitle>

<h1>References</h1>

@foreach (var reference in Data.References)
{
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input type="text" class="form-control" @bind="reference.Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="reference.Email" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input type="text" class="form-control" @bind="reference.Relationship" />
        </div>
        <button class="btn btn-outline-danger btn-sm align-self-end"
                @onclick="() => RemoveRef(reference)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add Reference</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddRef() => Data.References.Add(new());
    private void RemoveRef(ReferenceContact r) => Data.References.Remove(r);
    private void Back() => Navigation.NavigateTo("/apply/experience");

    private void Next()
    {
        Data.CompletedSteps.Add(3);
        Navigation.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase
@using sv_0caae1f81ebd4f21b031c134b9534000.Services

<PageTitle>Review — Job Application</PageTitle>

<h1>Review Your Application</h1>

@if (submitted)
{
    <div class="alert alert-success mt-3">
        <h4 class="alert-heading">Application Submitted!</h4>
        <p>Thank you, <strong>@Data.Name</strong>. We'll be in touch at <strong>@Data.Email</strong>.</p>
    </div>
}
else
{
    <h4>Personal Information</h4>
    <dl class="row">
        <dt class="col-sm-3">Name</dt>
